import{_ as a,o as i,c as t,ag as o}from"./chunks/framework.B9unkguw.js";const u=JSON.parse('{"title":"UI Overview","description":"","frontmatter":{},"headers":[],"relativePath":"en/qgc-user-guide/getting_started/ui_overview.md","filePath":"en/qgc-user-guide/getting_started/ui_overview.md"}'),n={name:"en/qgc-user-guide/getting_started/ui_overview.md"};function r(l,e,s,h,d,c){return i(),t("div",null,e[0]||(e[0]=[o('<h1 id="ui-overview" tabindex="-1">UI Overview <a class="header-anchor" href="#ui-overview" aria-label="Permalink to &quot;UI Overview&quot;">​</a></h1><p>QGroundControl is organized into a small number of top-level views, each accessed from the toolbar on the left side of the screen.</p><h2 id="toolbar" tabindex="-1">Toolbar <a class="header-anchor" href="#toolbar" aria-label="Permalink to &quot;Toolbar&quot;">​</a></h2><p>The toolbar is always visible and provides:</p><ul><li><strong>View switching</strong> — click the <strong>Q</strong> icon in the toolbar to open the view selector, then choose Fly, Plan, or any other view.</li><li><strong>View-specific content</strong> — the rest of the toolbar changes based on the current view, showing relevant status and controls for that view.</li></ul><h2 id="main-views" tabindex="-1">Main Views <a class="header-anchor" href="#main-views" aria-label="Permalink to &quot;Main Views&quot;">​</a></h2><h3 id="fly-view" tabindex="-1">Fly View <a class="header-anchor" href="#fly-view" aria-label="Permalink to &quot;Fly View&quot;">​</a></h3><p>The primary view while your vehicle is in the air. It shows a live map with the vehicle position, a heads-up display (HUD) with attitude and speed, and an instrument panel with telemetry values. Action buttons let you arm, take off, land, return to launch, and more.</p><p>See: <a href="./../fly_view/fly_view.html">Fly View</a></p><h3 id="plan-view" tabindex="-1">Plan View <a class="header-anchor" href="#plan-view" aria-label="Permalink to &quot;Plan View&quot;">​</a></h3><p>Used before flight to create and upload autonomous missions. You can place waypoints on the map, configure survey patterns, set geofence boundaries, and define rally points. Missions are uploaded to the vehicle over the active link.</p><p>See: <a href="./../plan_view/plan_view.html">Plan View</a></p><h3 id="vehicle-configuration" tabindex="-1">Vehicle Configuration <a class="header-anchor" href="#vehicle-configuration" aria-label="Permalink to &quot;Vehicle Configuration&quot;">​</a></h3><p>Configure your vehicle&#39;s firmware, airframe, sensors, flight modes, and safety settings. This view walks you through each setup step with a sidebar checklist. Available options vary depending on the connected firmware (PX4 or ArduPilot).</p><p>See: <a href="./../setup_view/firmware.html">Vehicle Setup</a></p><h3 id="analyze-view" tabindex="-1">Analyze View <a class="header-anchor" href="#analyze-view" aria-label="Permalink to &quot;Analyze View&quot;">​</a></h3><p>Tools for post-flight analysis and debugging:</p><ul><li><strong>Log Download</strong> — retrieve onboard flight logs.</li><li><strong>GeoTag Images</strong> — stamp survey photos with GPS coordinates.</li><li><strong>MAVLink Console</strong> — send commands directly to the autopilot.</li><li><strong>MAVLink Inspector</strong> — view raw MAVLink messages in real time.</li></ul><p>See: <a href="./../analyze_view/">Analyze</a></p><h3 id="application-settings" tabindex="-1">Application Settings <a class="header-anchor" href="#application-settings" aria-label="Permalink to &quot;Application Settings&quot;">​</a></h3><p>Persistent application preferences organized by category — general behavior, fly view layout, map providers, video streaming, RTK/NTRIP, telemetry logging, and more.</p>',21)]))}const g=a(n,[["render",r]]);export{u as __pageData,g as default};
